mapper.select:
select l.*, case when l.type = 'article' then i.title when l.type = 'post' then p.title when l.type = 'news' then n.title else '' end as introductionTitle, case when l.type = 'article' then i.content when l.type = 'post' then p.content when l.type = 'news' then n.content else '' end as introductionDescription, case when l.type = 'article' then i.img when l.type = 'post' then '' when l.type = 'news' then n.img else '' end as introductionImg from `like` l left join `introduction` i on l.type = 'article' and l.introduction_id = i.id left join `post` p on l.type = 'post' and l.introduction_id = p.id left join `news` n on l.type = 'news' and l.introduction_id = n.id where l.user_id = #{userId}
and l.type = #{type}
order by l.time desc
